import React, { useState, useEffect } from 'react'
import { NavHeader } from '../components/nav-header'
import { HeroSection } from '../components/hero-section'
import { AuthCard } from '../components/auth-card'
import { Footer } from '../components/footer'

export default function Home() {
  const [showAuth, setShowAuth] = useState(false);

  useEffect(() => {
    const handleHashChange = () => {
      setShowAuth(window.location.hash === '#login' || window.location.hash === '#register');
    };
    window.addEventListener('hashchange', handleHashChange);
    handleHashChange();
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  return (
    <main className={`relative w-full min-h-screen flex flex-col overflow-x-hidden ${!showAuth ? 'landing-bg' : 'bg-white'}`}>
      {/* Navigation */}
      <NavHeader />

      {/* Main Content */}
      <div className="relative z-10 flex-1 flex flex-col items-center justify-center w-full">
        {!showAuth ? (
          <HeroSection />
        ) : (
          <div className="flex items-center justify-center px-6 lg:px-12 py-12 lg:py-0 flex-1 w-full max-w-md">
            <div className="w-full">
              <AuthCard />
              <button 
                onClick={() => window.location.hash = ''}
                className="mt-6 w-full text-center text-sm font-bold text-gray-400 hover:text-primary transition-colors"
              >
                ← Back to Home
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Footer */}
      <Footer />
    </main>
  )
}
